import java.util.HashMap;

class Main {
  public static void main(String[] args) {
    // Keys are Strings, Values are Integers
    HashMap<String, Integer> userAges = new HashMap<String, Integer>();

    userAges.put("alex24", 28);
    userAges.put("sam_smith", 19);
    userAges.put("pro_gamer", 31);

    // Look up Sam's age instantly without looping!
    int age = userAges.get("sam_smith");
    System.out.println("Sam is " + age);
  }
}
